#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0; getchar();
    for(int i=0;i<T;++i){
        char name[105];
        if(!fgets(name, sizeof(name), stdin)) break;
        size_t len = strlen(name);
        if(len && name[len-1]=='\n') name[len-1]='\0';
        int level; scanf("%d", &level); getchar();
        printf("Name: %s\n", name);
        printf("Level: %d\n", level);
        printf("Strength: 10\n");
        printf("Intelligence: 10\n");
        printf("Agility: 10\n");
    }
    return 0;
}

