code.Java:
import java.io.*;

class Character{String name;int level;Character(String n,int l){name=n;level=l;}}
class Warrior{int strength=10;}
class Mage{int intelligence=10;}
class Rogue{int agility=10;}
class PlayerCharacter extends Character{int strength;int intelligence;int agility;PlayerCharacter(String n,int l){super(n,l);strength=10;intelligence=10;agility=10;}
    void display(){
        System.out.println("Name: "+name);
        System.out.println("Level: "+level);
        System.out.println("Strength: "+strength);
        System.out.println("Intelligence: "+intelligence);
        System.out.println("Agility: "+agility);
    }
}
public class Main{
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        int T=Integer.parseInt(br.readLine().trim());
        for(int i=0;i<T;i++){
            String name=br.readLine();
            int level=Integer.parseInt(br.readLine().trim());
            PlayerCharacter pc=new PlayerCharacter(name,level);
            pc.display();
        }
    }
}

